patch:
--- a/priority_encoder.vhd
+++ b/priority_encoder.vhd
@@ -1,20 +1,20 @@
 library ieee;
 use ieee.std_logic_1164.all;

 entity priority_encoder is
   port(
     req_0 : in std_logic;
     req_1 : in std_logic;
     req_2 : in std_logic;
     req_3 : in std_logic;
     grant : out std_logic_vector(1 downto 0)
   );
 end entity;

 architecture rtl of priority_encoder is
 begin
-  process(req_0)
+  process(req_0, req_1, req_2, req_3)
   begin
     if req_3 = '1' then
       grant <= "11";
     elsif req_2 = '1' then
       grant <= "10";
     elsif req_1 = '1' then
       grant <= "01";
     else
       grant <= "00";
     end if;
   end process;
 end rtl;

